import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"通用沟通句型总览","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/common-templates.md","filePath":"english-speaking/common-templates.md"}'),t={name:"english-speaking/common-templates.md"};function s(h,l,o,n,d,p){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="通用沟通句型总览" tabindex="-1">通用沟通句型总览 <a class="header-anchor" href="#通用沟通句型总览" aria-label="Permalink to “通用沟通句型总览”">​</a></h1><blockquote><p>这一页是整个口语模块的“句型地图”。<br> 你不需要一次背完，而是要按场景分批记。</p></blockquote><hr><h2 id="一、建议优先掌握的-8-类表达" tabindex="-1">一、建议优先掌握的 8 类表达 <a class="header-anchor" href="#一、建议优先掌握的-8-类表达" aria-label="Permalink to “一、建议优先掌握的 8 类表达”">​</a></h2><ol><li><strong>打招呼与寒暄</strong></li><li><strong>自我介绍与介绍别人</strong></li><li><strong>提问与确认</strong></li><li><strong>请求帮助与表达需求</strong></li><li><strong>表达观点与态度</strong></li><li><strong>会议与工作沟通</strong></li><li><strong>电话 / 视频沟通</strong></li><li><strong>结束对话与礼貌收尾</strong></li></ol><hr><h2 id="二、推荐记忆方式" tabindex="-1">二、推荐记忆方式 <a class="header-anchor" href="#二、推荐记忆方式" aria-label="Permalink to “二、推荐记忆方式”">​</a></h2><p>不要把句子当成孤立内容去死记，建议这样练：</p><ul><li>先记一个核心句型</li><li>再替换主语、时间、地点、动作</li><li>然后自己口头造 3-5 句</li></ul><p>例如：</p><ul><li><code>Could you help me with this?</code></li><li><code>Could you help me with this file?</code></li><li><code>Could you help me with this report?</code></li><li><code>Could you help me with this issue?</code></li></ul><hr><h2 id="三、本模块句型分组" tabindex="-1">三、本模块句型分组 <a class="header-anchor" href="#三、本模块句型分组" aria-label="Permalink to “三、本模块句型分组”">​</a></h2><h3 id="_1-日常通用口语" tabindex="-1">1. 日常通用口语 <a class="header-anchor" href="#_1-日常通用口语" aria-label="Permalink to “1. 日常通用口语”">​</a></h3><ul><li>打招呼</li><li>感谢</li><li>道歉</li><li>请求帮助</li><li>表达不懂</li><li>表达喜欢 / 不喜欢</li><li>结束对话</li></ul><p>入口：</p><ul><li><a href="/my-vitepress-site/english-speaking/templates-daily.html">日常通用口语模板</a></li></ul><h3 id="_2-工作沟通口语" tabindex="-1">2. 工作沟通口语 <a class="header-anchor" href="#_2-工作沟通口语" aria-label="Permalink to “2. 工作沟通口语”">​</a></h3><ul><li>交代任务</li><li>反馈进度</li><li>说明问题</li><li>请求支持</li><li>对齐信息</li><li>礼貌催办</li></ul><p>入口：</p><ul><li><a href="/my-vitepress-site/english-speaking/templates-work.html">工作沟通口语模板</a></li></ul><h3 id="_3-会议表达口语" tabindex="-1">3. 会议表达口语 <a class="header-anchor" href="#_3-会议表达口语" aria-label="Permalink to “3. 会议表达口语”">​</a></h3><ul><li>开场</li><li>补充观点</li><li>同意 / 不同意</li><li>打断与接回话题</li><li>总结</li><li>收尾</li></ul><p>入口：</p><ul><li><a href="/my-vitepress-site/english-speaking/templates-meeting.html">会议表达口语模板</a></li></ul><h3 id="_4-电话-视频沟通" tabindex="-1">4. 电话 / 视频沟通 <a class="header-anchor" href="#_4-电话-视频沟通" aria-label="Permalink to “4. 电话 / 视频沟通”">​</a></h3><ul><li>确认声音</li><li>请求重复</li><li>网络卡顿</li><li>转入正题</li><li>留言 / 回拨</li></ul><p>入口：</p><ul><li><a href="/my-vitepress-site/english-speaking/templates-call.html">电话/视频沟通模板</a></li></ul><h3 id="_5-社交寒暄口语" tabindex="-1">5. 社交寒暄口语 <a class="header-anchor" href="#_5-社交寒暄口语" aria-label="Permalink to “5. 社交寒暄口语”">​</a></h3><ul><li>初次见面</li><li>聊工作 / 学习</li><li>聊兴趣</li><li>邀请</li><li>礼貌拒绝</li></ul><p>入口：</p><ul><li><a href="/my-vitepress-site/english-speaking/templates-social.html">社交寒暄口语模板</a></li></ul><hr><h2 id="四、建议你的训练节奏" tabindex="-1">四、建议你的训练节奏 <a class="header-anchor" href="#四、建议你的训练节奏" aria-label="Permalink to “四、建议你的训练节奏”">​</a></h2><h3 id="每天-20-分钟就够" tabindex="-1">每天 20 分钟就够 <a class="header-anchor" href="#每天-20-分钟就够" aria-label="Permalink to “每天 20 分钟就够”">​</a></h3><ul><li>5 分钟：跟读</li><li>10 分钟：背句型</li><li>5 分钟：自己替换关键词复述</li></ul><h3 id="每周做一次输出" tabindex="-1">每周做一次输出 <a class="header-anchor" href="#每周做一次输出" aria-label="Permalink to “每周做一次输出”">​</a></h3><ul><li>选一个场景</li><li>连续说 1-3 分钟</li><li>不会说的地方，再回头补句型</li></ul><hr><h2 id="五、这套模块的目标" tabindex="-1">五、这套模块的目标 <a class="header-anchor" href="#五、这套模块的目标" aria-label="Permalink to “五、这套模块的目标”">​</a></h2><p>不是让你学成“考试英语”，而是让你先具备：</p><ul><li>能打招呼</li><li>能说明需求</li><li>能进行基础工作沟通</li><li>能在常见场景中自然开口</li></ul>',43)])])}const u=i(t,[["render",s]]);export{m as __pageData,u as default};
